    // Handle 0 specifically if the loop condition is n > 0
    if (n === 0) return 0;

    let temp = Math.abs(n);
    while (temp > 0) {
        sum += temp % 10;
        temp = Math.floor(temp / 10);
    }
    return sum;
}

