    // --- Base Case: i = 0 ---
    const target_d0 = digitSum[0];
    for (let v = 0; v <= MAX_VAL; v++) {
        if (sumDigits(v) === target_d0) {
            dp_prev[v] = 1;
        }
    }

    // --- DP Transitions: i = 1 to N-1 ---
    for (let i = 1; i < N; i++) {
        const target_di = digitSum[i];
        let dp_current = new Array(MAX_VAL + 1).fill(0);

        // 1. Calculate Prefix Sums for dp_prev
        // prefix_sum[v] = sum(dp_prev[u] for u=0 to v)
        let prefix_sum = new Array(MAX_VAL + 1).fill(0);
        let current_sum = 0;
        for (let v = 0; v <= MAX_VAL; v++) {
            current_sum = (current_sum + dp_prev[v]) % MOD;
            prefix_sum[v] = current_sum;
        }

        // 2. Calculate dp_current[v]
        for (let v = 0; v <= MAX_VAL; v++) {
            // Check constraint 3: A_i must have the required digit sum
            if (sumDigits(v) === target_di) {
                // Constraint 2: A_i >= A_{i-1}. 
                // The number of valid prefixes ending in u <= v is prefix_sum[v].
                dp_current[v] = prefix_sum[v];
            }
        }

        // Update for next iteration
        dp_prev = dp_current;
    }

    // --- Final Result ---
    // The total count is the sum of all valid arrays ending at any value v.
    let total_count = 0;
    for (let v = 0; v <= MAX_VAL; v++) {
        total_count = (total_count + dp_prev[v]) % MOD;
    }

    return total_count;
}

